    leia_ponto("Digite as coordenadas 2: ", &vertice2);

    struct ponto vertice3;
    leia_ponto("Digite as coordenadas 1: ", &vertice3);

    double area = area_triangulo(vertice1, vertice2, vertice3);
    printf("Área do triângulo: %.2f.\n", area);
}

